use std::sync::{RwLock, Arc};

struct ConfigStore {
    settings: RwLock<std::collections::HashMap<String, String>>
}

impl ConfigStore {
    fn new() -> Self {
        ConfigStore { 
            settings: RwLock::new(std::collections::HashMap::new())
        }
    }

    fn read_setting(&self, key: &str) -> Option<String> {
        let reader = self.settings.read().unwrap();
        reader.get(key).cloned()
    }

    fn write_setting(&self, key: String, value: String) {
        let mut writer = self.settings.write().unwrap();
        writer.insert(key, value);
    }
}

fn main() {
    let shared_config = Arc::new(ConfigStore::new());
    let config_clone_reader = Arc::clone(&shared_config);

    let reader_handle = std::thread::spawn(move || {
        for _i in 0..3 {
            std::thread::sleep(std::time::Duration::from_millis(50));
            if let Some(val) = config_clone_reader.read_setting("job_status") {
                println!("Reader Thread: Successfully read status: {}", val);
            }
        }
    });

    let config_clone_writer = Arc::clone(&shared_config);
    let writer_handle = std::thread::spawn(move || {
        std::thread::sleep(std::time::Duration::from_millis(100));
        config_clone_writer.write_setting("job_status".to_string(), "SUCCESS".to_string());
        println!("Writer Thread: Updated status to SUCCESS.");
    });

    reader_handle.join().unwrap();
    writer_handle.join().unwrap();
}

use std::sync::{Arc, RwLock};
use std::thread;
use std::time::Duration;
use std::collections::HashMap;

struct StateStore {
    data: RwLock<HashMap<String, String>>,
}

impl StateStore {
    fn new() -> Self {
        StateStore { data: RwLock::new(HashMap::new()) }
    }

    fn read_value(&self, key: &str) -> Option<String> {
        match self.data.read() {
            Ok(read_guard) => read_guard.get(key).cloned(),
            Err(_) => None,
        }
    }

    fn write_value(&self, key: &str, value: String) -> Result<(), String> {
        match self.data.write() {
            Ok(mut write_guard) => {
                write_guard.insert(key.to_string(), value);
                Ok(())
            },
            Err(_) => Err(String::from("Failed to acquire write lock"))
        }
    }
}

fn main() {
    let store = Arc::new(StateStore::new());
    let store_clone = Arc::clone(&store);

    for i in 1..=3 {
        let store_thread = Arc::clone(&store_clone);
        thread::spawn(move || {
            println!("Reader Thread: Attempting read operations...");
            for j in 0..2 {
                if let Some(val) = store_thread.read_value("config_key") {
                    println!("Reader Thread: Successfully read value: {}n", val);
                }
                thread::sleep(Duration::from_millis(50));
            }
        });
    }

    thread::sleep(Duration::from_millis(100));

    let writer = Arc::clone(&store); 
    let writer_handle = thread::spawn(move || {
        println!("Writer Thread: Attempting to acquire write lock and update state...");
        if let Err(e) = writer.write_value("config_key", format!("updated_at_{}n", std::time::SystemTime::now().duration_since(std::time::UNIX_EPOCH).unwrap().as_millis())) {
            println!("Writer Thread Error: {}", e);
        }
    });

    writer_handle.join().unwrap();
    thread::sleep(Duration::from_millis(100));

    for i in 4..=6 {
        let store_thread = Arc::clone(&store_clone);
        thread::spawn(move || {
            println!("Reader Thread: Attempting final read operation...");
            if let Some(val) = store_thread.read_value("config_key") {
                println!("Reader Thread: Final value read: {}n", val);
            }
        });
    }
}

